import React, { useState } from "react";

const ERROR_IMG_SRC =
  "data:image/svg+xml;base64,";

export function ImageWithFallback({ src, alt, style, className, ...rest }) {
  const [error, setError] = useState(false);

  const handleError = () => {
    setError(true);
  };

  return (
    <img
      src={error ? ERROR_IMG_SRC : src}
      alt={alt || "image"}
      className={className}
      style={style}
      onError={handleError}
      {...rest}
    />
  );
}